# Use nm or objdump to find the closest symbol for those addresses
DBG="/tmp/libmonosgen-2.0.so.dbg"
aarch64-linux-gnu-nm -C "$DBG" 2>/dev/null | sort | awk -v addr1="2f4b20" -v addr2="2f4c84" '
{
  if ($1 <= addr1) { prev1 = $0 }
  if ($1 <= addr2) { prev2 = $0 }
  if ($1 > addr1 && !done1) { print "0x2f4b20 -> " prev1; done1=1 }
  if ($1 > addr2 && !done2) { print "0x2f4c84 -> " prev2; done2=1 }
}' | head -4

